// ================================================================
// 1. OBTENCIÓN ROBUSTA DE DATOS (WEBHOOK VS GRAPHQL)
// ================================================================
let webhookNode;
let webhookBody;
let webhookHeaders;

try {
    // Intentamos leer el nodo "Webhook2" explícitamente
    if ($('Webhook2') && $('Webhook2').first()) {
        webhookNode = $('Webhook2').first().json;
    } else {
        // Fallback: Si no se llama "Webhook2", usamos el primer input disponible
        webhookNode = $input.all()[0].json;
    }
} catch (error) {
    webhookNode = {};
}

// Normalización: Asegurar que tenemos headers y body disponibles
if (webhookNode.headers && webhookNode.body) {
    webhookHeaders = webhookNode.headers;
    webhookBody = webhookNode.body;
} else if ($input.item.json.headers && $input.item.json.body) {
    webhookHeaders = $input.item.json.headers;
    webhookBody = $input.item.json.body;
} else {
    try {
        const whSource = $('Webhook2').first().json;
        webhookHeaders = whSource.headers;
        webhookBody = whSource.body;
    } catch(e) {
        webhookHeaders = {};
        webhookBody = {};
    }
}

const topic = webhookHeaders["x-shopify-topic"] || "";
const body = webhookBody || {};

// Variables de salida
let customerId = "";
let amountToProcess = 0;
// CAMBIO: Inicializamos con el texto deseado en lugar de null
let discountCode = "No encontrado"; 

// ================================================================
// 2. LÓGICA PRINCIPAL (PEDIDOS VS DEVOLUCIONES)
// ================================================================

if (topic.includes('orders/create')) {
    // ------------------------------------------------------------
    // CASO: NUEVO PEDIDO
    // ------------------------------------------------------------

    if (body.customer && body.customer.admin_graphql_api_id) {
        customerId = body.customer.admin_graphql_api_id;
    }

    if (body.discount_codes && body.discount_codes.length > 0) {
        discountCode = body.discount_codes[0].code;
    } else if (body.discount_applications && body.discount_applications.length > 0) {
        discountCode = body.discount_applications[0].title;
    }

    const totalDiscounts = parseFloat(body.total_discounts || "0");
    if (totalDiscounts > 0) {
        amountToProcess = parseFloat(body.total_price);
    } else {
        amountToProcess = 0;
    }

} else if (topic.includes('refunds/create')) {
    // ------------------------------------------------------------
    // CASO: DEVOLUCIÓN (REFUND)
    // ------------------------------------------------------------

    let orderData = null;
    try {
        orderData = $input.item.json.data ? $input.item.json.data.order : null;
    } catch(e) {}

    if (orderData && orderData.customer) {
         customerId = orderData.customer.id;

         if (orderData.discountCodes && orderData.discountCodes.length > 0) {
             const codeItem = orderData.discountCodes[0];
             discountCode = (typeof codeItem === 'string') ? codeItem : codeItem.code;
         } 
    } else {
         customerId = body.order_id; 
    }

    const transactions = body.transactions || [];
    const totalRefunded = transactions.reduce((acc, curr) => {
        return acc + parseFloat(curr.amount || 0);
    }, 0);

    amountToProcess = -Math.abs(totalRefunded);
}

// ================================================================
// 3. RETORNO FINAL
// ================================================================

// Doble seguridad: Si por alguna razón la lógica anterior asignó un valor vacío o nulo
if (!discountCode || discountCode === "") {
    discountCode = "No encontrado";
}

return {
    json: {
        customerId: customerId,
        amountToProcess: amountToProcess,
        discountCode: discountCode
    }
};

