mutation updateMetafields($metafields: [MetafieldsSetInput!]!) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      key
      value
    }
    userErrors {
      field
      message
    }
  }
}

mutation removeCustomerTags($id: ID!, $tags: [String!]!) {
  tagsRemove(id: $id, tags: $tags) {
    userErrors {
      field
      message
    }
    node {
      id
    }
  }
}

query getOrderCompleteDetails($id: ID!) {
  order(id: $id) {
    id
    name
    createdAt
    processedAt
    displayFinancialStatus
    displayFulfillmentStatus
    tags
    note
    email
    phone
    sourceIdentifier
    app {
      name
    }

    # 1. CLIENTE
    customer {
      id
      firstName
      lastName
      email
      numberOfOrders
    }

    # 2. DINERO Y TOTALES
    currentSubtotalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
    }
    totalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
    }
    totalReceivedSet {
      shopMoney {
        amount
        currencyCode
      }
    }
    totalDiscountsSet {
      shopMoney {
        amount
        currencyCode
      }
    }

    # DETALLE DE DESCUENTOS
    discountApplications(first: 10) {
      edges {
        node {
          targetSelection
          allocationMethod
          value {
            ... on MoneyV2 {
              amount
              currencyCode
            }
            ... on PricingPercentageValue {
              percentage
            }
          }
          ... on DiscountCodeApplication {
            code
          }
          ... on ManualDiscountApplication {
            title
            description
          }
          ... on AutomaticDiscountApplication {
            title
          }
          ... on ScriptDiscountApplication {
            title
          }
        }
      }
    }

    # 3. LÍNEAS DE PRODUCTO
    lineItems(first: 50) {
      edges {
        node {
          id
          title
          variantTitle
          sku
          quantity
          originalTotalSet {
            shopMoney {
              amount
              currencyCode
            }
          }
          variant {
            id
            price
          }
        }
      }
    }

    # 4. CUMPLIMIENTOS (Fulfillments) - SECCIÓN CORREGIDA
    fulfillments(first: 10) {
      id
      name
      status
      createdAt
      # 'trackingCompany' eliminado. Ahora se pide dentro de trackingInfo:
      trackingInfo {
        company
        number
        url
      }
      location {
        name
      }
      fulfillmentLineItems(first: 20) {
        edges {
          node {
            quantity
            lineItem {
              title
              variantTitle
            }
          }
        }
      }
    }

    # 5. DEVOLUCIONES (Refunds)
    refunds(first: 10) {
      id
      createdAt
      note
      refundLineItems(first: 20) {
        edges {
          node {
            quantity
            lineItem {
              title
              variantTitle
              sku
            }
            subtotalSet {
              shopMoney {
                amount
                currencyCode
              }
            }
          }
        }
      }
    }

    # 6. EVENTOS (Timeline)
    events(first: 50) {
      edges {
        node {
          id
          message
          createdAt
        }
      }
    }
  }
}

